import { toString } from 'langium/generate';

import { Artifact } from '../artifact-generator.js';
import { JavaClientAPIGeneratorConfig, toPath } from '../java-gen-utils.js';
import { toNodeTree } from '../util.js';

export function generateResult(artifactConfig: JavaClientAPIGeneratorConfig): Artifact {
	const packageName = artifactConfig.rootPackageName;

	const node = toNodeTree(`
// Generated by RSD - Do not modify
package ${packageName};

import java.util.function.Consumer;
import java.util.function.Function;
import java.util.function.Supplier;

public sealed interface Result<T, E> {
    public boolean isOk();

    public boolean isErr();

    public Result<T, E> onOk(Consumer<T> consumer);

    public Result<T, E> onErr(Consumer<E> consumer);

    public Result<T, E> or(Supplier<Result<T, E>> supplier);

    public default T orThrow() throws IllegalStateException {
        return orThrow(e -> new IllegalStateException(String.valueOf(e)));
    }

    public <X extends Throwable> T orThrow(Function<E, X> exceptionProvider) throws X;

    public record OK<T, E>(T value) implements Result<T, E> {
        @Override
        public boolean isOk() {
            return true;
        }

        @Override
        public boolean isErr() {
            return false;
        }

        @Override
        public Result<T, E> onOk(Consumer<T> consumer) {
            consumer.accept(value);
            return this;
        }

        @Override
        public Result<T, E> onErr(Consumer<E> consumer) {
            return this;
        }

        @Override
        public Result<T, E> or(Supplier<Result<T, E>> supplier) {
            return this;
        }

        @Override
        public <X extends Throwable> T orThrow(Function<E, X> exceptionProvider) {
            return value;
        }
    }

    public record ERR<T, E>(E error) implements Result<T, E> {
        @Override
        public boolean isOk() {
            return false;
        }

        @Override
        public boolean isErr() {
            return true;
        }

        @Override
        public Result<T, E> onOk(Consumer<T> consumer) {
            return this;
        }

        @Override
        public Result<T, E> onErr(Consumer<E> consumer) {
            consumer.accept(error);
            return this;
        }

        @Override
        public Result<T, E> or(Supplier<Result<T, E>> supplier) {
            return supplier.get();
        }

        @Override
        public <X extends Throwable> T orThrow(Function<E, X> exceptionProvider) throws X {
            throw exceptionProvider.apply(error);
        }
    }

    public static <T, E> Result<T, E> ok(T value) {
        return new OK<>(value);
    }

    public static <T, E> Result<T, E> err(E error) {
        return new ERR<>(error);
    }
}
`);

	return {
		name: 'Result.java',
		content: toString(node, '\t'),
		path: toPath(artifactConfig.targetFolder, packageName),
	};
}
